import { useRef } from 'react';

// export default Home;

function Home() {
  const imageRefs = useRef([]);

  const handleMouseMove = (event, index) => {
    const image = imageRefs.current[index];
    const rect = image.getBoundingClientRect();

    const dx = event.clientX - rect.left - rect.width / 2;
    const dy = event.clientY - rect.top - rect.height / 2;

    // Adjust the movement distance as needed
    const maxDistance = 10;
    const distance = Math.min(Math.sqrt(dx * dx + dy * dy), maxDistance);
    const angle = Math.atan2(dy, dx);

    image.style.transform = `translate(${Math.cos(angle) * distance}px, ${
      Math.sin(angle) * distance
    }px)`;
  };
  return (
    <div className="w-full h-[100vh] flex items-center justify-center p-10 relative">
      <div
        className="absolute top-0 left-0 w-full h-full"
        style={{
          backgroundImage: "url('/fondo6.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          opacity: 0.4,
        }}
      />
      <div className="w-full h-full z-10 flex items-center justify-between">
        {/* Images left */}
        <div className=" h-full relative flex items-center">
          <div className="ml-40 relative">
            <img
              className="rounded-lg absolute -left-20 transition-transform transform moving-image"
              width={150}
              height={150}
              style={{ top: 'calc(50% - 75px)' }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
              ref={(el) => (imageRefs.current[0] = el)}
              onMouseMove={(e) => handleMouseMove(e, 0)}
            />
            <img
              className="rounded-lg absolute -left-20 transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{ top: 'calc(50% - 75px)' }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            <img
              className="rounded-lg absolute left-16 transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{ top: 'calc(85%)' }}
              src="/Foto4.HEIC"
              alt="Imagen 2"
            />
          </div>
        </div>
        {/* Text center */}
        <div className="h-full flex flex-col justify-center items-center gap-5">
          <h3 className="text-[#6d7561] md:text-2xl font-medium text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-4xl md:text-4xl font-bold text-center">
            Anto & Kevin
          </h1>
          <a
            href="#ConfirmAttendance"
            className="text-[#6d7561] text-2xl underline hover:text-[#6d756190]"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>
        {/* Images right */}
        <div className="h-full relative flex items-center justify-end">
          <div className="mr-40 relative">
            <img
              className="rounded-lg transition-transform transform hover:scale-110"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            <img
              className="rounded-lg absolute -right-28 transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{ top: 'calc(50% - 75px)' }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
